def major(k):
    if any(t in k for t in ["임종","호스피스","연명","부모님마지막","부모임종","사전연명"]):
        return "1. 임종·생애말기"
    if any(t in k for t in ["사망신고","사망후","부모님사망","안심상속원스톱","장례후"]):
        return "2. 사후 행정·절차"
    if any(t in k for t in ["상조","장례식장","장례지도사","유공자","부산장례","빈소","부고"]):
        return "3. 상조·장례 서비스"
    if any(t in k for t in ["제사","차례","명절","추석","49재","기일","투고","전세트","설음식","설상차림","설날음식","설명절","설차례"]):
        return "4. 제사·추모·명절"
    if any(t in k for t in ["유언","유서","디지털유산","효도계약","상속미리준비","사전상속","사전증여","후견계약"]):
        return "5. 유언·생전준비"
    if any(t in k for t in ["상속","증여","유류분","한정승인","한정상속","후견","유증","대습",
        "입양","친양자","성본","인지청구","친자","친생자","기여분","양도세","양도소득"]):
        return "6. 상속·증여(법률·세무)"
    return "Z. 잡음(제외)"

TXN = ["비용","수수료","대행","변호사","세무사","법무사","로펌","법무법인","상담","주문",
       "업체","공증","대리","선임","수임","감정평가","컨설팅"]
DOC = ["양식","서식","신청서","신고서","서류","계약서","동의서","협의서","위임장","증명서",
       "신고","등기","합의서","공고","집행문","결정문","각서","공정증서","의향서"]

def intent(k):
    if any(t in k for t in TXN): return "거래·서비스형"
    if any(t in k for t in DOC): return "서식·행정형"
    return "정보·개념형"

def to_num(s):
    s = s.strip().strip('"')
    if "<" in s: return 5
    if s in ("", "-"): return 0
    try: return int(float(s.replace(",", "")))
    except ValueError: return 0

rows = []
seen = set()
for src, raw in RAW.items():
    raw = raw.replace("\\<", "<")
    body = raw.split("월평균클릭률(모바일),,", 1)[1]
    for tok in body.split():
        rec = next(csv.reader(io.StringIO(tok)))
        if len(rec) < 3: continue
        kw = rec[0].strip()
        if not kw or kw in seen: continue
        seen.add(kw)
        pc, mo = to_num(rec[1]), to_num(rec[2])
        comp = rec[7].strip() if len(rec) > 7 else ""
        rows.append({"kw": kw, "total": pc+mo, "pc": pc, "mo": mo,
                     "comp": comp, "major": major(kw), "intent": intent(kw), "src": src})

# 정렬: 대분류(잡음 맨뒤) → 총검색수 desc
rows.sort(key=lambda r: (r["major"], -r["total"]))

def dump(path, recs, cols=True):
    with open(path, "w", newline="", encoding="utf-8-sig") as f:
        w = csv.writer(f)
        w.writerow(["연관키워드","총검색수","PC검색수","모바일검색수","경쟁정도","대분류","세부의도","출처파일"])
        for r in recs:
            w.writerow([r["kw"], r["total"], r["pc"], r["mo"], r["comp"], r["major"], r["intent"], r["src"]])

dump("docs/research/keywords_combined.csv", rows)            # 전체(잡음 포함)
meaningful = [r for r in rows if not r["major"].startswith("Z")]
dump("docs/research/keywords_meaningful.csv", meaningful)    # 잡음 제외
import os
print("\n-- 파일 크기 --")
for p in ["docs/research/keywords_combined.csv","docs/research/keywords_meaningful.csv"]:
    print(f"{p}: {os.path.getsize(p):,}B / {sum(1 for _ in open(p))-1}행")

# 요약
from collections import defaultdict
agg = defaultdict(lambda: [0,0])
for r in rows:
    agg[r["major"]][0] += 1
    agg[r["major"]][1] += r["total"]
print(f"총 키워드(중복제거): {len(rows)}")
print(f"{'대분류':<24}{'키워드수':>8}{'총검색수':>12}")
for m in sorted(agg):
    print(f"{m:<24}{agg[m][0]:>8}{agg[m][1]:>12,}")
noise = agg.get("Z. 잡음(제외)", [0,0])
print(f"\n잡음(제외) {noise[0]}개 / 검색수 {noise[1]:,}")
print(f"유효 키워드 {len(rows)-noise[0]}개")
